+  template <typename U, ENABLE_IF(!std::is_pointer<U>::value && !HAS_METASPACE_POINTERS_DO(U))>
+  void metaspace_pointers_do_impl(MetaspaceClosure* it) {
+    // No pointers to follow
+  }
+
+  // E.g., Array<Annotation>
